/* Asset paths for embedded theme */
#define NFI_THEME_CSS_PATH "/_nfi_theme/styles.css"
#define NFI_THEME_JS_PATH "/_nfi_theme/fancyindex.js"

/* Asset enumeration */
typedef enum {
    NFI_THEME_ASSET_CSS,
    NFI_THEME_ASSET_JS,
    NFI_THEME_ASSET_NONE
} nfi_theme_asset_t;

/* Lookup table for theme assets */
typedef struct {
    const char          *path;
    size_t               path_len;
    const u_char        *mime;
    size_t               mime_len;
    const u_char        *data;
    size_t               data_len;
} nfi_theme_asset_info_t;

